-- =============================================================================
-- IRDP — Import ระบบจองรถ (เดิม) → van_bookings  (107 รายการ)
-- นำเข้าเป็น status='cancelled' (ประวัติ) เพื่อเลี่ยง exclusion constraint van_no_overlap
-- requester map จากอีเมล, ผู้ร่วมเดินทางเก็บในช่องวัตถุประสงค์ (purpose)
-- vehicle = คันแรกในระบบ (รถตู้ส่วนกลาง). รันครั้งเดียว.
-- =============================================================================
insert into van_bookings
  (vehicle_id, requester_id, destination, purpose, start_at, end_at, status, has_tollway, has_fuel)
select
  (select id from vehicles order by name limit 1),
  (select id from employees e where lower(e.email) = lower(v.email)),
  v.destination, v.purpose, v.start_at::timestamptz, v.end_at::timestamptz,
  'cancelled'::booking_status_t, v.has_tollway, v.has_fuel
from (values
  ('chattanun@irdp.org','กรุงเทพ','ดูงานในประเทศ PEP22','2026-10-27T08:30:00+07:00','2026-10-27T17:00:00+07:00',true,true),
